/**
 * search.js — Hugo PaperMod animated search widget
 *
 * Requires: Fuse.js (loaded via CDN in extend_head.html)
 * Requires: /index.json (generated by layouts/index.json)
 */

(function () {
  'use strict';

  // ─── DOM refs ────────────────────────────────────────────────
  const widget   = document.getElementById('search-widget');
  const toggle   = document.getElementById('search-toggle');
  const box      = document.getElementById('search-box');
  const input    = document.getElementById('search-input');
  const clearBtn = document.getElementById('search-clear');
  const results  = document.getElementById('search-results');
  const overlay  = document.getElementById('search-overlay');

  if (!widget || !toggle || !input) return; // guard if partial not loaded

  // ─── State ───────────────────────────────────────────────────
  let fuse       = null;
  let indexLoaded = false;
  let loadingIdx  = false;
  let activeIndex = -1;
  let debounceTimer;

  // ─── Fuse.js options ─────────────────────────────────────────
  const FUSE_OPTIONS = {
    keys: [
      { name: 'title',   weight: 0.7 },
      { name: 'summary', weight: 0.2 },
      { name: 'tags',    weight: 0.1 },
    ],
    threshold:     0.35,   // 0 = exact, 1 = match anything
    includeScore:  true,
    includeMatches: true,
    minMatchCharLength: 2,
    ignoreLocation: true,
  };

  // ─── Load search index ───────────────────────────────────────
  async function loadIndex() {
    if (indexLoaded || loadingIdx) return;
    loadingIdx = true;

    showLoading();

    try {
      const res  = await fetch('/index.json');
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      fuse        = new Fuse(data, FUSE_OPTIONS);
      indexLoaded = true;
    } catch (err) {
      console.warn('[search] Failed to load index.json:', err);
    } finally {
      loadingIdx = false;
      hideResults();
    }
  }

  // ─── Open / close ────────────────────────────────────────────
  function openSearch() {
    widget.classList.add('is-open');
    toggle.setAttribute('aria-expanded', 'true');
    box.removeAttribute('aria-hidden');
    overlay.removeAttribute('hidden');

    // 打开时：按钮显示为「关闭搜索」模式（搜索图标）
    clearBtn.removeAttribute('hidden');
    clearBtn.classList.add('is-close-mode');
    clearBtn.setAttribute('aria-label', '关闭搜索');

    // Wait for CSS transition, then focus
    setTimeout(() => input.focus(), 340);

    if (!indexLoaded && !loadingIdx) loadIndex();
  }

  function closeSearch() {
    widget.classList.remove('is-open');
    toggle.setAttribute('aria-expanded', 'false');
    box.setAttribute('aria-hidden', 'true');
    overlay.setAttribute('hidden', '');
    hideResults();
    input.value = '';
    clearBtn.setAttribute('hidden', '');
    clearBtn.classList.remove('is-close-mode');
    clearBtn.setAttribute('aria-label', '清除搜索');
    activeIndex = -1;
  }

  // ─── Results rendering ───────────────────────────────────────
  function showLoading() {
    results.innerHTML = '<li class="search-loading">正在加载索引</li>';
    results.removeAttribute('hidden');
  }

  function hideResults() {
    results.setAttribute('hidden', '');
    results.innerHTML = '';
    activeIndex = -1;
  }

  function highlightText(text, indices) {
    if (!indices || !indices.length) return escapeHtml(text);
    let result   = '';
    let lastIndex = 0;
    // Fuse returns [start, end] pairs (inclusive)
    for (const [start, end] of indices) {
      result += escapeHtml(text.slice(lastIndex, start));
      result += `<mark>${escapeHtml(text.slice(start, end + 1))}</mark>`;
      lastIndex = end + 1;
    }
    result += escapeHtml(text.slice(lastIndex));
    return result;
  }

  function escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function getMatchIndices(matchArr, key) {
    const m = matchArr && matchArr.find(m => m.key === key);
    return m ? m.indices : null;
  }

  function renderResults(fuseResults) {
    results.innerHTML = '';

    if (!fuseResults.length) {
      results.innerHTML = '<li class="search-no-results">没有找到相关文章 😔</li>';
      results.removeAttribute('hidden');
      return;
    }

    fuseResults.slice(0, 8).forEach((r, i) => {
      const { item, matches } = r;
      const li = document.createElement('li');
      li.setAttribute('role', 'option');
      li.setAttribute('id', `search-result-${i}`);

      const titleHtml   = highlightText(item.title,   getMatchIndices(matches, 'title'));
      const summaryHtml = item.summary
        ? highlightText(item.summary, getMatchIndices(matches, 'summary'))
        : '';

      // Build tags HTML
      const tagsHtml = (item.tags || []).slice(0, 3)
        .map(t => `<span class="tag">${escapeHtml(t)}</span>`)
        .join('');

      li.innerHTML = `
        <a class="search-result-item" href="${escapeHtml(item.permalink)}" tabindex="-1">
          <div class="search-result-title">${titleHtml}</div>
          ${summaryHtml ? `<div class="search-result-summary">${summaryHtml}</div>` : ''}
          <div class="search-result-meta">
            <span>${escapeHtml(item.date || '')}</span>
            ${tagsHtml}
          </div>
        </a>
      `;

      results.appendChild(li);
    });

    results.removeAttribute('hidden');
    activeIndex = -1;
  }

  // ─── Keyboard navigation in dropdown ─────────────────────────
  function getItems() {
    return Array.from(results.querySelectorAll('.search-result-item'));
  }

  function setActive(idx) {
    const items = getItems();
    items.forEach((el, i) => el.classList.toggle('is-active', i === idx));
    if (items[idx]) {
      items[idx].scrollIntoView({ block: 'nearest' });
      input.setAttribute('aria-activedescendant', `search-result-${idx}`);
    } else {
      input.removeAttribute('aria-activedescendant');
    }
    activeIndex = idx;
  }

  // ─── Search execution ─────────────────────────────────────────
  function doSearch(query) {
    if (!query.trim()) { hideResults(); return; }
    if (!fuse) {
      if (!indexLoaded) showLoading();
      return;
    }
    const hits = fuse.search(query);
    renderResults(hits);
  }

  // ─── Event listeners ─────────────────────────────────────────

  // Toggle button
  toggle.addEventListener('click', () => {
    widget.classList.contains('is-open') ? closeSearch() : openSearch();
  });

  // Overlay click → close
  overlay.addEventListener('click', closeSearch);

  // Input typing
  input.addEventListener('input', (e) => {
    const val = e.target.value;

    // 有文字：显示 × 清空模式；无文字：显示搜索关闭模式
    if (val) {
      clearBtn.classList.remove('is-close-mode');
      clearBtn.setAttribute('aria-label', '清除搜索');
    } else {
      clearBtn.classList.add('is-close-mode');
      clearBtn.setAttribute('aria-label', '关闭搜索');
    }

    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => doSearch(val), 160);
  });

  // Keyboard nav
  input.addEventListener('keydown', (e) => {
    const items = getItems();
    if (!items.length) {
      if (e.key === 'Escape') closeSearch();
      return;
    }

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setActive(Math.min(activeIndex + 1, items.length - 1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setActive(Math.max(activeIndex - 1, 0));
        break;
      case 'Enter':
        if (activeIndex >= 0 && items[activeIndex]) {
          items[activeIndex].click();
        }
        break;
      case 'Escape':
        if (!results.hidden) {
          hideResults();
        } else {
          closeSearch();
        }
        break;
    }
  });

  // Clear / Close button
  clearBtn.addEventListener('click', () => {
    if (clearBtn.classList.contains('is-close-mode')) {
      // 无文字时：关闭搜索框
      closeSearch();
    } else {
      // 有文字时：清空输入，切换回关闭模式
      input.value = '';
      clearBtn.classList.add('is-close-mode');
      clearBtn.setAttribute('aria-label', '关闭搜索');
      hideResults();
      input.focus();
    }
  });

  // Global keyboard shortcut: "/" or Ctrl+K to open
  document.addEventListener('keydown', (e) => {
    // Don't trigger when typing in other inputs
    if (e.target.matches('input, textarea, [contenteditable]')) return;

    if (e.key === '/' || (e.ctrlKey && e.key === 'k') || (e.metaKey && e.key === 'k')) {
      e.preventDefault();
      if (!widget.classList.contains('is-open')) openSearch();
    }
  });

  // Close on outside click
  document.addEventListener('click', (e) => {
    if (!widget.contains(e.target) && !overlay.contains(e.target)) {
      if (widget.classList.contains('is-open')) closeSearch();
    }
  });

  // Re-run search after index loads
  const _origLoadIndex = loadIndex;
  async function loadIndexAndSearch() {
    await _origLoadIndex.call(this);
    if (input.value.trim()) doSearch(input.value.trim());
  }
  // replace the closure reference used in openSearch
  window.__searchLoadIndex = loadIndexAndSearch;

})();
